<script>
import UserInfo from './components/UserInfo.vue'
import SkillTags from './components/SkillTags.vue'

export default {
  components: {
    UserInfo,
    SkillTags
  },
  data() {
    return {
      userInfo: {
        name: '王小明',
        grade: '25级',
        college: '软件工程学院'
      },
      authInfo: {
        name: '张伟',
        studentId: '102XXXXXXX',
        campusEmail: 'xxx@stu.ecnu.cn'
      },
      skills: ['Python', 'Vue.js', 'Rust'],
      showAuthInfo: false,
      showSkillModal: false,
      skillForm: {
        stack: '',
        experience: ''
      }
    }
  },
  methods: {
    onUploadAvatar() {
      uni.showToast({
        title: '上传头像功能待接入',
        icon: 'none'
      })
    },
    goProfile() {
      uni.navigateTo({
        url: '/pages/user/profile'
      })
    },
    openAuthInfo() {
      this.showAuthInfo = true
    },
    closeAuthInfo() {
      this.showAuthInfo = false
    },
    openSkillModal() {
      this.skillForm.stack = ''
      this.skillForm.experience = ''
      this.showSkillModal = true
    },
    closeSkillModal() {
      this.showSkillModal = false
    },
    confirmAddSkill() {
      const value = this.skillForm.stack && this.skillForm.stack.trim()
      if (!value) {
        uni.showToast({
          title: '请先填写技术栈',
          icon: 'none'
        })
        return
      }
      this.skills.push(value)
      this.closeSkillModal()
    },
    goMyProjects(type) {
      uni.navigateTo({
        url: `/pages/user/my-projects?type=${type}`
      })
    },
    goSettings() {
  // 保留按钮点击反馈，但不跳转（避免报错）
  uni.showToast({
    title: '系统设置功能即将上线',
    icon: 'none',
    duration: 1500
  })
